"""Ingest benchmark samples generated by frontier models in the browser.

Frontier models (ChatGPT / Claude / Gemini web) are prompted with the template in
`build_benchmark.md` (Phụ lục A) to emit batches of ~10 samples. Paste each batch
into a file under `data/bench/browser_raw/`, then run this script to validate,
dedup, and convert everything into the Llama Factory `conversations` benchmark.

Accepts loosely-formatted input per file:
    - {"samples": [ {...}, ... ]}
    - a bare list [ {...}, ... ]
    - one JSON object per line (jsonl)
    - any of the above wrapped in a ```json ... ``` markdown fence

Each sample is expected to carry its own `pattern`, plus optional `intent` and
`context_required`. Validation (turn structure, hallucinated numbers, negation /
compound markers, …) reuses `validate_sample` from `build_benchmark.py` so the
browser-generated set obeys the exact same gates as the API-generated one.

Usage:
    python -m src.data.ingest_browser_bench data/bench/browser_raw/*.json
    python -m src.data.ingest_browser_bench batch1.json batch2.json \
        --output data/bench/dialogues_bench.jsonl --report

Output: Llama Factory `conversations` jsonl (default data/bench/dialogues_bench.jsonl).
"""
from __future__ import annotations

import argparse
import json
import re
from pathlib import Path

from src.data.build_benchmark import (
    PATTERN_PROMPTS,
    to_lf_record,
    validate_sample,
)
from src.data.prompts import SYSTEM_PROMPT_FOR_TRAINING

VALID_PATTERNS = set(PATTERN_PROMPTS.keys())
FENCE_RE = re.compile(r"```(?:json)?\s*(.*?)```", re.DOTALL)


def _strip_fence(text: str) -> str:
    """Return the first fenced code block if present, else the raw text."""
    m = FENCE_RE.search(text)
    return m.group(1).strip() if m else text.strip()


def _parse_payload(text: str) -> list[dict]:
    """Parse one browser file into a flat list of raw sample dicts."""
    text = _strip_fence(text)
    if not text:
        return []

    # Try whole-blob JSON first (object with "samples", or a bare list).
    try:
        obj = json.loads(text)
    except json.JSONDecodeError:
        obj = None

    if isinstance(obj, dict) and isinstance(obj.get("samples"), list):
        return [s for s in obj["samples"] if isinstance(s, dict)]
    if isinstance(obj, list):
        return [s for s in obj if isinstance(s, dict)]
    if isinstance(obj, dict):  # a single sample object
        return [obj]

    # Fall back to jsonl: one object (or {"samples": [...]}) per line.
    out: list[dict] = []
    for line in text.splitlines():
        line = line.strip().rstrip(",")
        if not line:
            continue
        try:
            rec = json.loads(line)
        except json.JSONDecodeError:
            continue
        if isinstance(rec, dict) and isinstance(rec.get("samples"), list):
            out.extend(s for s in rec["samples"] if isinstance(s, dict))
        elif isinstance(rec, dict):
            out.append(rec)
    return out


def ingest(paths: list[Path], report: bool = False) -> tuple[list[dict], dict]:
    """Load → validate → dedup. Returns (lf_records, stats)."""
    stats: dict[str, int] = {
        "files": 0, "raw": 0, "no_pattern": 0,
        "bad_pattern": 0, "rejected": 0, "duplicate": 0, "kept": 0,
    }
    reject_reasons: dict[str, int] = {}
    seen: set[tuple[str, str]] = set()
    records: list[dict] = []

    for path in paths:
        if not path.exists():
            print(f"  WARN: missing {path}")
            continue
        stats["files"] += 1
        for raw in _parse_payload(path.read_text(encoding="utf-8")):
            stats["raw"] += 1
            pattern = (raw.get("pattern") or "").strip()
            if not pattern:
                stats["no_pattern"] += 1
                continue
            if pattern not in VALID_PATTERNS:
                stats["bad_pattern"] += 1
                continue

            # context_required=False may legitimately be single-turn "keep as is"
            # with a rewrite identical to the final turn; everything else must be
            # a hard ≥3-turn case with a non-trivial rewrite.
            is_keep_as_is = raw.get("context_required") is False
            sample, reason = validate_sample(
                raw, pattern,
                min_turns=1 if is_keep_as_is else 3,
                allow_equal_rewrite=is_keep_as_is,
            )
            if sample is None:
                stats["rejected"] += 1
                reject_reasons[reason] = reject_reasons.get(reason, 0) + 1
                continue

            key = (sample.turns[-1]["content"], sample.rewrite)
            if key in seen:
                stats["duplicate"] += 1
                continue
            seen.add(key)

            rec = to_lf_record(sample, SYSTEM_PROMPT_FOR_TRAINING)
            # Carry browser-supplied labels the API pipeline doesn't produce.
            intent = (raw.get("intent") or "").strip()
            if intent:
                rec["meta"]["intent"] = intent
            ctx = raw.get("context_required")
            if isinstance(ctx, bool):
                rec["meta"]["context_required"] = ctx
            rec["meta"]["source"] = "browser_frontier"
            records.append(rec)
            stats["kept"] += 1

    if report and reject_reasons:
        stats["_reject_reasons"] = reject_reasons  # type: ignore[assignment]
    return records, stats


def main() -> None:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("inputs", nargs="+", type=Path,
                        help="Browser-gen JSON/JSONL files (globs expanded by the shell)")
    # Separate file by default: never clobber the API-generated dialogues_bench.jsonl.
    parser.add_argument("--output", type=Path,
                        default=Path("data/bench/dialogues_bench_browser.jsonl"))
    parser.add_argument("--append", action="store_true",
                        help="Append to --output (dedup vs. existing) instead of overwriting")
    parser.add_argument("--report", action="store_true",
                        help="Print per-reason rejection breakdown")
    args = parser.parse_args()

    records, stats = ingest(args.inputs, report=args.report)

    existing: list[dict] = []
    if args.append and args.output.exists():
        for line in args.output.open(encoding="utf-8"):
            line = line.strip()
            if line:
                existing.append(json.loads(line))
        seen = {
            (r["conversations"][-2]["value"], r["conversations"][-1]["value"])
            for r in existing
        }
        deduped = []
        for r in records:
            key = (r["conversations"][-2]["value"], r["conversations"][-1]["value"])
            if key in seen:
                stats["duplicate"] += 1
                continue
            seen.add(key)
            deduped.append(r)
        records = deduped

    args.output.parent.mkdir(parents=True, exist_ok=True)
    with args.output.open("w", encoding="utf-8") as f:
        for r in existing + records:
            f.write(json.dumps(r, ensure_ascii=False) + "\n")

    total = len(existing) + len(records)
    print(f"Ingested {stats['raw']} raw from {stats['files']} file(s) → "
          f"kept {stats['kept']} new, {stats['duplicate']} dup, "
          f"{stats['rejected']} rejected, {stats['bad_pattern']} bad-pattern, "
          f"{stats['no_pattern']} no-pattern")
    print(f"Wrote {total} samples to {args.output}")

    # Distribution snapshot
    by_pat: dict[str, int] = {}
    by_dom: dict[str, int] = {}
    ctx_true = 0
    for r in existing + records:
        m = r.get("meta", {})
        by_pat[m.get("pattern", "?")] = by_pat.get(m.get("pattern", "?"), 0) + 1
        by_dom[m.get("domain", "?")] = by_dom.get(m.get("domain", "?"), 0) + 1
        if m.get("context_required") is True:
            ctx_true += 1
    if total:
        print(f"\ncontext_required: {ctx_true}/{total} = {ctx_true / total:.1%} "
              f"(target ~66.7%)")
        print("Pattern:", dict(sorted(by_pat.items())))
        print("Domain :", dict(sorted(by_dom.items(), key=lambda x: -x[1])))
    if args.report and "_reject_reasons" in stats:
        print("\nReject reasons:", stats["_reject_reasons"])


if __name__ == "__main__":
    main()
